async def generate_request(obj: GenerateReqInput, request: Request):
    """Handle a generate request."""
    if envs.SGLANG_ENABLE_REQUEST_HEADER_OVERRIDES.get():
        apply_header_overrides(obj, request.headers)
    if obj.stream:

        async def stream_results() -> AsyncIterator[bytes]:
            try:
                async for out in _global_state.tokenizer_manager.generate_request(
                    obj, request
                ):
                    yield b"data: " + dumps_json(out) + b"\n\n"
            except ValueError as e:
                # A client disconnect also surfaces here. It's a client-side
                # cancellation, not a server error or bad input -- log it and
                # stop (the request was already aborted upstream) instead of
                # emitting a 400.
                if request is not None and await request.is_disconnected():
                    logger.info(f"[http_server] Client disconnected: {e}")
                    return
                out = {
                    "error": {
                        "message": str(e),
                        "type": "invalid_request_error",
                        "code": 400,
                        "retryable": False,

                    if recv_obj.time_stats is not None
                    else None
                )
                completion_tokens = (
                    recv_obj.completion_tokens[i]
                    if not isinstance(recv_obj, BatchEmbeddingOutput)
                    else 0
                )
                meta_info.update(
                    state.time_stats.convert_to_output_meta_info(
                        scheduler_time_stats, completion_tokens
                    )
                )

            del self.rid_to_state[rid]

            # Mark ongoing LoRA request as finished.
            if self.enable_lora and state.obj.lora_path:
                asyncio.create_task(self.lora_registry.release(state.obj.lora_id))

        if out_dict is not None:
            state.out_list.append(out_dict)
            pending_notify[rid] = state

            if len(pending_notify) >= batch_notify_size:
                for s in pending_notify.values():
                    s.event.set()
                pending_notify = {}
                await asyncio.sleep(0)

        if self.enable_metrics and state.obj.log_metrics:
            self.collect_metrics(state, recv_obj, i)
        if self.dump_requests_folder and state.finished and state.obj.log_metrics:
            self.dump_requests(state, out_dict)
        if self.crash_dump_folder and state.finished and state.obj.log_metrics:
            self.record_request_for_crash_dump(state, out_dict)

    # handle_loop awaits next recv immediately
    for s in pending_notify.values():
        s.event.set()

